import pandas as pd
import matplotlib.pyplot as plt

def task_func(df):
    try:
        if not isinstance(df, pd.DataFrame) or 'Status' not in df.columns:
            raise ValueError("The DataFrame does not contain the 'Status' column.")

        statuses = df['Status'].value_counts()
        labels = statuses.index.tolist()
        sizes = statuses.values.tolist()

        fig1, ax1 = plt.subplots(figsize=(6, 6))
        ax1.pie(sizes, labels=labels, autopct='%1.1f%%', startangle=90)
        ax1.axis('equal')

        return tuple(ax1)
    except Exception as e:
        print(f"An error occurred: {e}")
